// Age-appropriate vocabulary pools — high-cap banks for every age group.
import { VOCAB_POOL } from './vocab-pool';

type VocabEntry = { word: string; meaning: string; example: string };

type AgeGroup = '5-7' | '8-10' | '11-13' | '14-17' | '18-21' | '22+';

const AGE_VOCAB_TARGET_COUNTS: Record<AgeGroup, number> = {
  '5-7': 1000,
  '8-10': 1000,
  '11-13': 1000,
  '14-17': 1000,
  '18-21': 1000,
  '22+': 1000,
};

