function buildContextExample(ageGroup: AgeGroup, word: string, variantIndex: number) {
  const templates = AGE_EXAMPLE_TEMPLATES[ageGroup];
  const template = templates[variantIndex % templates.length];
  return template.replaceAll('{word}', word);
}

const POOL_ELIGIBLE_AGE_GROUPS: AgeGroup[] = ['11-13', '14-17', '18-21', '22+'];
const AGE_BULK_EXTRA_COUNT = 230;
const AGE_EXTRA_VOCAB_COUNT = 600 + AGE_BULK_EXTRA_COUNT;

function buildExtraVocab(ageGroup: AgeGroup, offset: number, count = AGE_EXTRA_VOCAB_COUNT): VocabEntry[] {
  if (!POOL_ELIGIBLE_AGE_GROUPS.includes(ageGroup)) return [];
  if (VOCAB_POOL.length === 0) return [];
  return Array.from({ length: count }, (_, index) => {
    const source = VOCAB_POOL[(offset + index) % VOCAB_POOL.length];
    return { ...source };
  });
}

const EXTRA_VOCAB_BY_AGE: Record<AgeGroup, VocabEntry[]> = {
  '5-7': buildExtraVocab('5-7', 0),
  '8-10': buildExtraVocab('8-10', 120),
  '11-13': buildExtraVocab('11-13', 240),
  '14-17': buildExtraVocab('14-17', 360),
  '18-21': buildExtraVocab('18-21', 480),
  '22+': buildExtraVocab('22+', 600),
};

function expandAgeGroup(entries: VocabEntry[], ageGroup: AgeGroup, offset: number, targetCount: number): VocabEntry[] {
  const base = entries.map((entry) => ({ ...entry }));
  if (base.length >= targetCount) {
    return base.slice(0, targetCount);
  }

  const seen = new Set<string>();
  const poolForAge = POOL_ELIGIBLE_AGE_GROUPS.includes(ageGroup) ? VOCAB_POOL : [];
  const sourceEntries = [...base, ...poolForAge].filter((entry) => {
    const key = entry.word.trim().toLowerCase();
    if (!key || seen.has(key)) return false;
    seen.add(key);
    return true;
  });
  const expanded = [...base];
  let index = 0;

  while (expanded.length < targetCount && sourceEntries.length > 0) {
    const source = sourceEntries[(offset + index) % sourceEntries.length];
    const variantIndex = Math.floor((offset + index) / sourceEntries.length);
    expanded.push({
      word: source.word,
      meaning: source.meaning,
      example: source.example || buildContextExample(ageGroup, source.word, variantIndex),
    });
    index += 1;
  }

  return expanded.slice(0, targetCount);
}

